 int32_t calculate_operand_dims_count(const DnnOperand *oprd)
 {
     int32_t result = 1;
     for (int i = 0; i < 4; ++i)
         result *= oprd->dims[i];

     return result;
 }

 int32_t calculate_operand_data_length(const DnnOperand* oprd)
