                 s->bytestream += n;
                 ptr           += linesize;
             }
         }
         break;
     case AV_PIX_FMT_YUV420P:
     case AV_PIX_FMT_YUV420P9:
     case AV_PIX_FMT_YUV420P10:
         {
             unsigned char *ptr1, *ptr2;

             n        = avctx->width;
             ptr      = p->data[0];
             linesize = p->linesize[0];
             if (s->maxval >= 256)
                 n *= 2;
             if (n * avctx->height * 3 / 2 > s->bytestream_end - s->bytestream)
                 return AVERROR_INVALIDDATA;
             for (i = 0; i < avctx->height; i++) {
                 samplecpy(ptr, s->bytestream, n, s->maxval);
                 s->bytestream += n;
                 ptr           += linesize;
             }
             ptr1 = p->data[1];
             ptr2 = p->data[2];
             n >>= 1;
             h = avctx->height >> 1;
             for (i = 0; i < h; i++) {
                 samplecpy(ptr1, s->bytestream, n, s->maxval);
                 s->bytestream += n;
                 samplecpy(ptr2, s->bytestream, n, s->maxval);
                 s->bytestream += n;
                 ptr1 += p->linesize[1];
                 ptr2 += p->linesize[2];
             }
         }
         break;
     case AV_PIX_FMT_YUV420P16:
         {
             uint16_t *ptr1, *ptr2;
             const int f = (65535 * 32768 + s->maxval / 2) / s->maxval;
             unsigned int j, v;

             n        = avctx->width * 2;
             ptr      = p->data[0];
             linesize = p->linesize[0];
             if (n * avctx->height * 3 / 2 > s->bytestream_end - s->bytestream)
                 return AVERROR_INVALIDDATA;
             for (i = 0; i < avctx->height; i++) {
                 for (j = 0; j < n / 2; j++) {
                     v = AV_RB16(s->bytestream + 2*j);
                     ((uint16_t *)ptr)[j] = (v * f + 16384) >> 15;
                 }
                 s->bytestream += n;
                 ptr           += linesize;
             }
             ptr1 = (uint16_t*)p->data[1];
             ptr2 = (uint16_t*)p->data[2];
             n >>= 1;
             h = avctx->height >> 1;
             for (i = 0; i < h; i++) {
                 for (j = 0; j < n / 2; j++) {
                     v = AV_RB16(s->bytestream + 2*j);
                     ptr1[j] = (v * f + 16384) >> 15;
                 }
                 s->bytestream += n;

                 for (j = 0; j < n / 2; j++) {
                     v = AV_RB16(s->bytestream + 2*j);
                     ptr2[j] = (v * f + 16384) >> 15;
                 }
                 s->bytestream += n;

                 ptr1 += p->linesize[1] / 2;
                 ptr2 += p->linesize[2] / 2;
             }
         }
         break;
     case AV_PIX_FMT_GBRPF32:
         if (!s->half) {
-            if (avctx->width * avctx->height * 12 > s->bytestream_end - s->bytestream)
+            if (avctx->width * avctx->height * 12LL > s->bytestream_end - s->bytestream)
                 return AVERROR_INVALIDDATA;
             scale = 1.f / s->scale;
             if (s->endian) {
                 float *r, *g, *b;

                 r = (float *)p->data[2];
                 g = (float *)p->data[0];
                 b = (float *)p->data[1];
                 for (int i = 0; i < avctx->height; i++) {
                     for (int j = 0; j < avctx->width; j++) {
                         r[j] = av_int2float(AV_RL32(s->bytestream+0)) * scale;
                         g[j] = av_int2float(AV_RL32(s->bytestream+4)) * scale;
                         b[j] = av_int2float(AV_RL32(s->bytestream+8)) * scale;
